INSERT INTO `priv_query` (`id`, `name`, `description`, `is_template`, `export_count`, `export_last_date`, `user_id`, `realclass`) VALUES
(1, 'Agent of the Ticket', 'Can be used in Notification, to notify the agent of a Ticket.', 'yes', 0, NULL, 0, 'QueryOQL'),
(2, 'Agent of the Ticket unless the agent himself triggered the notification', 'Can be used in Notification, to notify the agent of a Ticket.\n      No email will be send if the person who triggered that notification is the agent himself.\n    ', 'yes', 0, NULL, 0, 'QueryOQL'),
(3, 'Caller and Contacts linked to the Ticket', 'Can be used in Notification, to notify the caller and all contacts associated to a Ticket', 'yes', 0, NULL, 0, 'QueryOQL'),
(4, 'Caller of the Ticket', 'To be used in Notification, to notify the caller of a Ticket', 'yes', 0, NULL, 0, 'QueryOQL'),
(5, 'Contacts linked to the Ticket', 'Can be used in Notification, to notify contacts associated to a Ticket', 'yes', 0, NULL, 0, 'QueryOQL'),
(6, 'Manager of the Ticket caller', 'Can be used in Ticket Notification, to notify the manager of the caller.', 'yes', 0, NULL, 0, 'QueryOQL'),
(7, 'Person who triggered the notification', 'Can be used in Notification, to notify the person whom by their action triggered the notification.\n      If used alone, it returns the person connected to iTop and running that query.\n    ', 'yes', 0, NULL, 0, 'QueryOQL'),
(8, 'Team members of the Ticket', 'Can be used in Notification, to notify the team members, to which the Ticket was dispatched.', 'yes', 0, NULL, 0, 'QueryOQL'),
(9, 'Team members of the Ticket other than the agent', 'Can be used in Notification, to notify the team members, to which the Ticket was dispatched.\n      The agent himself is excluded from that list.\n    ', 'yes', 0, NULL, 0, 'QueryOQL'),
(10, 'Team of the Ticket', 'Can be used in Notification, to notify the team generic email, to which the Ticket was dispatched.', 'yes', 0, NULL, 0, 'QueryOQL'),
(11, 'Contacts of a Functional CI', 'Can be used in Notification, to notify the Contacts linked to the Functional CI.', 'yes', 0, NULL, 0, 'QueryOQL'),
(12, 'Contacts of a Service', 'Can be used in Notification, to notify the Contacts linked to the Service.', 'yes', 0, NULL, 0, 'QueryOQL'),
(13, 'Contacts of a Contract', 'Can be used in Notification, to notify the Contacts linked to the Contract.', 'yes', 0, NULL, 0, 'QueryOQL');

